#include<bits/stdc++.h>
using namespace std;
int main() {
	string s;
	int k = 0;
	cin >> s >> k;
	int minj = 0;
	for (int i = 0; i < s.size(); i++) {
		if (s[i] == '0') {
			if ((i - minj + 1) - k > 0) break;
			for (int j = minj; j <= i; j++) s[j] = ' ';
			k -= (i - minj);
			minj = i + 1;
		}
	}
	int i = -1, j = 0;
	for (; (i < int(s.size())); ) {
		i++;
		while (s[i] == ' ' && (i < int(s.size()))) i++;
		j = i + 1;
		while (s[j] == ' ' && j < s.size()) j++;
		if (s[i] > s[j]) {
			if (k > 0) {
				k--;
				s[i] = ' ';
				j--;
					while (s[i] == ' ' && i>=0) i--;
					i--;
			}
		}
	}
	for (int i = s.size() - 1; i >= 0 && k > 0; i--) {
		k--;
		s[i] = ' ';
	}
	for (int i = 0; i < s.size(); i++) {
		if (s[i] != ' ') {
			cout << s[i];
		}
	}
	return 0;
}
